#include <unordered_map>
#include <vector>
#include <algorithm>

int mostFrequentEven(std::vector<int>& nums) {
    std::unordered_map<int, int> count;
    for (int num : nums) {
        if (num % 2 == 0) {
            count[num]++;
        }
    }
    int maxCount = 0;
    int result = -1;
    for (auto& pair : count) {
        if (pair.second > maxCount) {
            maxCount = pair.second;
            result = pair.first;
        } else if (pair.second == maxCount && pair.first < result) {
            result = pair.first;
        }
    }
    return result;
}
```

